import React, { useState, useEffect, useRef, useCallback } from 'react';
import CameraFeed, { CameraHandle } from './components/CameraFeed';
import LiveAudio from './components/LiveAudio';
import Timeline from './components/Timeline';
import { CapturedImage, MonitorSettings, ChatMessage } from './types';
import { 
  analyzeImage, 
  sendMessage, 
  generateSpeech, 
  getFastResponse, 
  generateGrowthReport,
  decodeAudio,
  decodeAudioData
} from './services/geminiService';
import { 
  Leaf, 
  Play, 
  Square, 
  Mic, 
  MessageSquare, 
  MapPin, 
  Globe, 
  BrainCircuit, 
  Volume2,
  Clock, 
  Zap,
  Eye,
  FileText,
  PlayCircle,
  EyeOff,
  Trash2,
  AlertTriangle,
  CheckCircle,
  Activity,
  Terminal,
  Settings,
  Camera,
  FastForward,
  Cpu,
  ChevronDown,
  ChevronUp,
  Siren,
  Radio,
  Tag,
  Calendar,
  Video,
  Sprout,
  Droplet,
  Sun,
  Flower,
  AlertCircle,
  Repeat,
  Power,
  HelpCircle,
  Lightbulb,
  X
} from 'lucide-react';

const App: React.FC = () => {
  const [active, setActive] = useState(false);
  const [isCameraEnabled, setIsCameraEnabled] = useState(true);
  const [images, setImages] = useState<CapturedImage[]>([]);
  const [settings, setSettings] = useState<MonitorSettings>({
    intervalHours: 1.5,
    autoAnalyze: false,
    wakeLockActive: true,
    facingMode: 'environment',
    resolution: 'med',
    playbackFps: 1,
    timestampPrecision: 'both',
    minConfidenceThreshold: 70,
    autoAdvance: true
  });
  const [selectedImage, setSelectedImage] = useState<CapturedImage | null>(null);
  const [liveMode, setLiveMode] = useState(false);
  const [playbackMode, setPlaybackMode] = useState(false);
  const [stealthMode, setStealthMode] = useState(false);
  const [showSettings, setShowSettings] = useState(true);
  const [chatMessages, setChatMessages] = useState<ChatMessage[]>([]);
  const [userInput, setUserInput] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [location, setLocation] = useState<{lat: number, lng: number} | undefined>(undefined);

  const cameraRef = useRef<CameraHandle>(null);
  const chatEndRef = useRef<HTMLDivElement>(null);
  const wakeLockRef = useRef<WakeLockSentinel | null>(null);

  // --- WAKE LOCK API ---
  // Keeps the screen on so the interval can run in the "background" (foreground with screen on)
  useEffect(() => {
    const requestWakeLock = async () => {
      if ('wakeLock' in navigator && active && settings.wakeLockActive) {
        try {
          wakeLockRef.current = await navigator.wakeLock.request('screen');
          console.log('Screen Wake Lock acquired');
        } catch (err: any) {
          console.error(`Wake Lock Error: ${err.name}, ${err.message}`);
        }
      }
    };

    const releaseWakeLock = async () => {
      if (wakeLockRef.current) {
        try {
          await wakeLockRef.current.release();
          wakeLockRef.current = null;
          console.log('Screen Wake Lock released');
        } catch (err) {
          console.error("Wake lock release error", err);
        }
      }
    };

    if (active) {
      requestWakeLock();
    } else {
      releaseWakeLock();
    }

    const handleVisibilityChange = () => {
      if (wakeLockRef.current !== null && document.visibilityState === 'visible' && active) {
        requestWakeLock();
      }
    };

    document.addEventListener('visibilitychange', handleVisibilityChange);
    return () => {
      releaseWakeLock();
      document.removeEventListener('visibilitychange', handleVisibilityChange);
    };
  }, [active, settings.wakeLockActive]);

  // --- INTERVAL CAPTURE ---
  useEffect(() => {
    let intervalId: NodeJS.Timeout;
    if (active) {
      console.log(`Starting monitoring. Next capture in ${settings.intervalHours} hours.`);
      intervalId = setInterval(() => {
        handleCapture();
      }, settings.intervalHours * 60 * 60 * 1000);
    }
    return () => clearInterval(intervalId);
  }, [active, settings.intervalHours]);

  // --- INITIALIZATION ---
  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (pos) => setLocation({ lat: pos.coords.latitude, lng: pos.coords.longitude }),
        (err) => console.warn("Geolocation failed", err)
      );
    }

    // Initial welcome message
    setChatMessages([{
      id: 'init',
      role: 'model',
      text: "Systems Online. I am Gaia. I can monitor your plants, detect health issues, and create time-lapse records. Set your interval frequency in Settings to begin autonomous monitoring.",
      timestamp: Date.now()
    }]);
  }, []);

  // --- HANDLERS ---

  const handleCapture = async () => {
    if (!cameraRef.current) return;

    const dataUrl = cameraRef.current.capture();
    if (dataUrl) {
      const newImage: CapturedImage = {
        id: crypto.randomUUID(),
        timestamp: Date.now(),
        dataUrl,
        analysis: undefined
      };

      setImages(prev => [...prev, newImage]);

      // Auto Analyze if enabled
      if (settings.autoAnalyze) {
        performAnalysis(newImage);
      }
    }
  };

  const performAnalysis = async (img: CapturedImage) => {
    setIsProcessing(true);
    try {
      const result = await analyzeImage(img.dataUrl, "Analyze this plant image. Identify the plant, growth stage, and check for any pests, diseases, or water stress. Be concise.");

      setImages(prev => prev.map(i => {
        if (i.id === img.id) {
          // Simple heuristic to set status tag based on text
          let status: CapturedImage['healthStatus'] = 'HEALTHY';
          const lower = result.toLowerCase();
          if (lower.includes('dead') || lower.includes('critical') || lower.includes('pest')) status = 'CRITICAL';
          else if (lower.includes('wilt') || lower.includes('yellow') || lower.includes('stress')) status = 'STRESSED';

          return { ...i, analysis: result, healthStatus: status };
        }
        return i;
      }));

      // Notify chat
      setChatMessages(prev => [...prev, {
        id: crypto.randomUUID(),
        role: 'system',
        text: `Analysis complete for snapshot ${img.id.slice(-4)}: ${result.slice(0, 100)}...`,
        timestamp: Date.now()
      }]);

    } catch (e) {
      console.error(e);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleSendMessage = async () => {
    if (!userInput.trim()) return;

    const userMsg: ChatMessage = {
      id: crypto.randomUUID(),
      role: 'user',
      text: userInput,
      timestamp: Date.now()
    };

    setChatMessages(prev => [...prev, userMsg]);
    setUserInput('');
    setIsProcessing(true);

    try {
      // Determine intent for tools
      const lower = userInput.toLowerCase();
      const useThinking = lower.includes('plan') || lower.includes('reason') || lower.includes('complex');
      const useSearch = lower.includes('search') || lower.includes('news') || lower.includes('latest');
      const useMaps = lower.includes('where') || lower.includes('location') || lower.includes('map') || lower.includes('nearby');

      const response = await sendMessage(
        chatMessages.map(m => ({ role: m.role, text: m.text })),
        userMsg.text,
        useThinking,
        useSearch,
        useMaps,
        location
      );

      setChatMessages(prev => [...prev, {
        id: crypto.randomUUID(),
        role: 'model',
        text: response.text || "I'm not sure how to respond to that.",
        timestamp: Date.now(),
        groundingUrls: response.groundingMetadata?.groundingChunks
          ?.map((c: any) => c.web ? { title: c.web.title, uri: c.web.uri } : null)
          .filter(Boolean)
      }]);

    } catch (e) {
      console.error(e);
      setChatMessages(prev => [...prev, {
        id: crypto.randomUUID(),
        role: 'system',
        text: "Error communicating with neural core.",
        timestamp: Date.now()
      }]);
    } finally {
      setIsProcessing(false);
      chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }
  };

  const handleGenerateReport = async () => {
    setIsProcessing(true);
    const logs = images
      .filter(i => i.analysis)
      .map(i => `[${new Date(i.timestamp).toLocaleDateString()}] ${i.analysis}`);

    if (logs.length === 0) {
      setChatMessages(prev => [...prev, { id: 'sys', role: 'system', text: "Not enough data for a report.", timestamp: Date.now()}]);
      setIsProcessing(false);
      return;
    }

    try {
      const report = await generateGrowthReport(logs);
      setChatMessages(prev => [...prev, {
        id: crypto.randomUUID(),
        role: 'model',
        text: report,
        timestamp: Date.now()
      }]);
    } catch (e) { console.error(e); }
    finally { setIsProcessing(false); }
  };

  return (
    <div className="flex flex-col h-screen bg-cyber-900 text-gray-200 overflow-hidden font-sans selection:bg-cyber-accent selection:text-black">

      {/* --- HEADER --- */}
      <header className="flex items-center justify-between px-4 py-3 bg-black/50 border-b border-cyber-700 backdrop-blur-md z-30">
        <div className="flex items-center gap-2">
          <Leaf className="text-cyber-accent animate-pulse" />
          <h1 className="text-lg font-bold tracking-widest text-white font-mono">
            CHRONOS<span className="text-cyber-accent">GAIA</span>
          </h1>
        </div>

        <div className="flex items-center gap-2">
          <button 
             onClick={() => setActive(!active)}
             className={`flex items-center gap-2 px-3 py-1.5 rounded-full font-mono text-xs font-bold transition-all ${active ? 'bg-cyber-accent text-black shadow-[0_0_15px_rgba(132,204,22,0.5)]' : 'bg-cyber-900 border border-gray-600 text-gray-400'}`}
          >
            {active ? <Square size={12} fill="currentColor" /> : <Play size={12} fill="currentColor" />}
            {active ? 'MONITORING' : 'STANDBY'}
          </button>

          <button onClick={() => setLiveMode(true)} className="p-2 hover:bg-white/10 rounded-full transition-colors text-cyber-success" title="Live Link">
             <Radio size={18} />
          </button>

          <button onClick={() => setShowSettings(!showSettings)} className={`p-2 hover:bg-white/10 rounded-full transition-colors ${showSettings ? 'text-white' : 'text-gray-500'}`}>
             <Settings size={18} />
          </button>
        </div>
      </header>

      {/* --- MAIN CONTENT --- */}
      <main className="flex-1 flex overflow-hidden relative">

        {/* LEFT COLUMN: Camera & Timeline */}
        <div className="flex-1 flex flex-col min-w-0 relative">

          {/* Camera Viewport */}
          <div className="flex-1 relative bg-black flex items-center justify-center overflow-hidden">
             {selectedImage ? (
                <div className="relative w-full h-full flex items-center justify-center bg-cyber-900">
                   <img src={selectedImage.dataUrl} className="max-w-full max-h-full object-contain" />
                   <button 
                     onClick={() => setSelectedImage(null)}
                     className="absolute top-4 right-4 p-2 bg-black/60 text-white rounded-full hover:bg-red-500 transition-colors"
                   >
                     <X size={20} />
                   </button>
                   {selectedImage.analysis && (
                     <div className="absolute bottom-4 left-4 right-4 bg-black/80 p-4 rounded border border-cyber-700 backdrop-blur-md">
                        <h3 className="text-cyber-accent font-mono text-xs mb-1">ANALYSIS LOG // {new Date(selectedImage.timestamp).toLocaleString()}</h3>
                        <p className="text-sm text-gray-300">{selectedImage.analysis}</p>
                     </div>
                   )}
                </div>
             ) : (
                <CameraFeed 
                  ref={cameraRef}
                  active={isCameraEnabled}
                  facingMode={settings.facingMode}
                  resolution={settings.resolution}
                  onResolutionChange={(r) => setSettings(s => ({ ...s, resolution: r }))}
                  className="w-full h-full"
                />
             )}

             {/* Status Overlay */}
             {active && !selectedImage && (
               <div className="absolute bottom-4 left-4 flex gap-2">
                 <div className="bg-black/60 backdrop-blur px-2 py-1 rounded border border-cyber-accent/30 flex items-center gap-2">
                    <Clock size={12} className="text-cyber-accent" />
                    <span className="text-[10px] font-mono">
                      NEXT: {new Date(Date.now() + settings.intervalHours * 3600000).toLocaleTimeString()}
                    </span>
                 </div>
                 {settings.wakeLockActive && (
                    <div className="bg-black/60 backdrop-blur px-2 py-1 rounded border border-cyber-accent/30 flex items-center gap-2" title="Screen Wake Lock Active">
                        <Sun size={12} className="text-yellow-400" />
                        <span className="text-[10px] font-mono text-yellow-400">AWAKE</span>
                    </div>
                 )}
               </div>
             )}
          </div>

          {/* Timeline Strip */}
          <div className="h-32 bg-cyber-900 border-t border-cyber-700 flex flex-col">
            <div className="flex items-center justify-between px-2 py-1 bg-black/20">
               <span className="text-[10px] font-mono text-gray-500 flex items-center gap-1">
                 <Calendar size={10} /> TIMELINE // {images.length} SNAPS
               </span>
               <div className="flex gap-2">
                  <button onClick={handleGenerateReport} className="text-[10px] font-mono text-cyber-success hover:text-white flex items-center gap-1">
                    <FileText size={10} /> REPORT
                  </button>
               </div>
            </div>
            <div className="flex-1 overflow-hidden">
               <Timeline images={images} onSelect={setSelectedImage} />
            </div>
          </div>
        </div>

        {/* RIGHT COLUMN: Chat & Settings */}
        <div className={`${showSettings ? 'w-80' : 'w-0'} transition-all duration-300 border-l border-cyber-700 bg-black/40 backdrop-blur-md flex flex-col`}>

           {/* Settings Panel */}
           <div className="p-4 border-b border-cyber-700 space-y-4 overflow-y-auto max-h-[40vh] custom-scrollbar">
              <h2 className="text-xs font-bold text-cyber-accent font-mono flex items-center gap-2">
                <Terminal size={12} /> SYSTEM CONFIGURATION
              </h2>

              <div className="space-y-1">
                <label className="text-[10px] font-mono text-gray-500">INTERVAL FREQUENCY (HOURS)</label>
                <div className="grid grid-cols-4 gap-1 mb-2">
                  {[0.5, 1.0, 1.5, 2.0, 4.0, 6.0, 12.0, 24.0].map((h) => (
                    <button
                      key={h}
                      onClick={() => setSettings(s => ({ ...s, intervalHours: h }))}
                      className={`text-[10px] py-1 border rounded transition-colors ${
                        settings.intervalHours === h 
                          ? 'bg-cyber-accent text-black border-cyber-accent font-bold' 
                          : 'bg-transparent border-gray-700 text-gray-400 hover:border-gray-500'
                      }`}
                    >
                      {h}h
                    </button>
                  ))}
                </div>
                <input 
                  type="range" 
                  min="0.1" 
                  max="24" 
                  step="0.1" 
                  value={settings.intervalHours}
                  onChange={(e) => setSettings(s => ({...s, intervalHours: parseFloat(e.target.value)}))}
                  className="w-full accent-cyber-accent h-1 bg-gray-700 rounded-lg appearance-none cursor-pointer"
                />
                <div className="flex justify-between text-[9px] font-mono text-gray-400 mt-1">
                  <span>Current: {settings.intervalHours} HRS</span>
                </div>
              </div>

              <div className="flex items-center justify-between">
                 <span className="text-[10px] font-mono text-gray-400">AUTO-ANALYSIS</span>
                 <button 
                   onClick={() => setSettings(s => ({...s, autoAnalyze: !s.autoAnalyze}))}
                   className={`w-8 h-4 rounded-full relative transition-colors ${settings.autoAnalyze ? 'bg-cyber-accent' : 'bg-gray-700'}`}
                 >
                   <div className={`absolute top-0.5 w-3 h-3 bg-white rounded-full transition-all ${settings.autoAnalyze ? 'left-4.5' : 'left-0.5'}`}></div>
                 </button>
              </div>

              <div className="flex items-center justify-between">
                 <div className="flex flex-col">
                    <span className="text-[10px] font-mono text-gray-400">PREVENT SLEEP</span>
                    <span className="text-[8px] text-gray-600">Keep screen on for background tasks</span>
                 </div>
                 <button 
                   onClick={() => setSettings(s => ({...s, wakeLockActive: !s.wakeLockActive}))}
                   className={`w-8 h-4 rounded-full relative transition-colors ${settings.wakeLockActive ? 'bg-cyber-accent' : 'bg-gray-700'}`}
                 >
                   <div className={`absolute top-0.5 w-3 h-3 bg-white rounded-full transition-all ${settings.wakeLockActive ? 'left-4.5' : 'left-0.5'}`}></div>
                 </button>
              </div>

              <div className="flex items-center justify-between">
                 <span className="text-[10px] font-mono text-gray-400">CAMERA FACING</span>
                 <button 
                   onClick={() => setSettings(s => ({...s, facingMode: s.facingMode === 'user' ? 'environment' : 'user'}))}
                   className="text-[10px] font-mono text-cyber-accent border border-cyber-accent px-2 py-0.5 rounded uppercase"
                 >
                   {settings.facingMode}
                 </button>
              </div>
           </div>

           {/* Chat Interface */}
           <div className="flex-1 flex flex-col min-h-0">
              <div className="p-2 border-b border-cyber-700 bg-black/20">
                 <h2 className="text-xs font-bold text-cyber-success font-mono flex items-center gap-2">
                   <BrainCircuit size={12} /> GAIA NEURAL LINK
                 </h2>
              </div>

              <div className="flex-1 overflow-y-auto p-4 space-y-4 custom-scrollbar">
                 {chatMessages.map((msg) => (
                   <div key={msg.id} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                      <div className={`max-w-[90%] p-3 rounded-lg text-xs leading-relaxed ${
                        msg.role === 'user' 
                          ? 'bg-cyber-accent/10 border border-cyber-accent/30 text-cyber-accent rounded-br-none' 
                          : msg.role === 'system'
                          ? 'bg-red-500/10 border border-red-500/30 text-red-200 font-mono'
                          : 'bg-cyber-800 border border-cyber-700 text-gray-300 rounded-bl-none'
                      }`}>
                        {msg.text}
                      </div>
                      {msg.groundingUrls && (
                        <div className="mt-1 flex flex-wrap gap-1">
                           {msg.groundingUrls.map((url, i) => (
                             <a key={i} href={url.uri} target="_blank" rel="noreferrer" className="text-[9px] text-blue-400 hover:underline flex items-center gap-1">
                               <Globe size={8} /> {url.title || 'Source'}
                             </a>
                           ))}
                        </div>
                      )}
                      <span className="text-[9px] text-gray-600 mt-1 font-mono">{new Date(msg.timestamp).toLocaleTimeString()}</span>
                   </div>
                 ))}
                 {isProcessing && (
                   <div className="flex items-center gap-2 text-cyber-accent text-xs font-mono animate-pulse">
                     <Cpu size={12} /> PROCESSING...
                   </div>
                 )}
                 <div ref={chatEndRef}></div>
              </div>

              <div className="p-3 bg-black/40 border-t border-cyber-700">
                 <div className="flex gap-2">
                   <input 
                     type="text" 
                     value={userInput}
                     onChange={(e) => setUserInput(e.target.value)}
                     onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
                     placeholder="Ask Gaia..."
                     className="flex-1 bg-black/50 border border-gray-700 rounded px-3 py-2 text-xs focus:outline-none focus:border-cyber-accent text-white font-mono"
                   />
                   <button 
                     onClick={handleSendMessage}
                     disabled={isProcessing}
                     className="p-2 bg-cyber-800 border border-cyber-700 rounded text-cyber-accent hover:bg-cyber-700 disabled:opacity-50"
                   >
                     <MessageSquare size={16} />
                   </button>
                 </div>
              </div>
           </div>
        </div>

      </main>

      {/* Live Overlay */}
      {liveMode && (
        <LiveAudio 
          onClose={() => setLiveMode(false)}
          onCapture={handleCapture}
          onTranscript={(text, isUser) => {
             // Optional: Add to main chat history for continuity
             if (!isUser) { // only model responses
                setChatMessages(prev => [...prev, {
                  id: crypto.randomUUID(),
                  role: 'model',
                  text: `[LIVE TRANSCRIPT] ${text}`,
                  timestamp: Date.now()
                }]);
             }
          }}
        />
      )}
    </div>
  );
};

export default App;

