                   onClick={() => setSettings(s => ({...s, wakeLockActive: !s.wakeLockActive}))}
                   className={`w-8 h-4 rounded-full relative transition-colors ${settings.wakeLockActive ? 'bg-cyber-accent' : 'bg-gray-700'}`}
                 >
                   <div className={`absolute top-0.5 w-3 h-3 bg-white rounded-full transition-all ${settings.wakeLockActive ? 'left-4.5' : 'left-0.5'}`}></div>
                 </button>
              </div>

              <div className="flex items-center justify-between">
                 <span className="text-[10px] font-mono text-gray-400">CAMERA FACING</span>
                 <button 
                   onClick={() => setSettings(s => ({...s, facingMode: s.facingMode === 'user' ? 'environment' : 'user'}))}
                   className="text-[10px] font-mono text-cyber-accent border border-cyber-accent px-2 py-0.5 rounded uppercase"
                 >
                   {settings.facingMode}
                 </button>
              </div>
           </div>

           {/* Chat Interface */}
           <div className="flex-1 flex flex-col min-h-0">
              <div className="p-2 border-b border-cyber-700 bg-black/20">
                 <h2 className="text-xs font-bold text-cyber-success font-mono flex items-center gap-2">
                   <BrainCircuit size={12} /> GAIA NEURAL LINK
                 </h2>
              </div>

              <div className="flex-1 overflow-y-auto p-4 space-y-4 custom-scrollbar">
                 {chatMessages.map((msg) => (
                   <div key={msg.id} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                      <div className={`max-w-[90%] p-3 rounded-lg text-xs leading-relaxed ${
                        msg.role === 'user' 
                          ? 'bg-cyber-accent/10 border border-cyber-accent/30 text-cyber-accent rounded-br-none' 
                          : msg.role === 'system'
                          ? 'bg-red-500/10 border border-red-500/30 text-red-200 font-mono'
                          : 'bg-cyber-800 border border-cyber-700 text-gray-300 rounded-bl-none'
                      }`}>
                        {msg.text}
                      </div>
                      {msg.groundingUrls && (
                        <div className="mt-1 flex flex-wrap gap-1">
                           {msg.groundingUrls.map((url, i) => (
                             <a key={i} href={url.uri} target="_blank" rel="noreferrer" className="text-[9px] text-blue-400 hover:underline flex items-center gap-1">
                               <Globe size={8} /> {url.title || 'Source'}
                             </a>
                           ))}
                        </div>
                      )}
                      <span className="text-[9px] text-gray-600 mt-1 font-mono">{new Date(msg.timestamp).toLocaleTimeString()}</span>
                   </div>
                 ))}
                 {isProcessing && (
                   <div className="flex items-center gap-2 text-cyber-accent text-xs font-mono animate-pulse">
                     <Cpu size={12} /> PROCESSING...
                   </div>
                 )}
                 <div ref={chatEndRef}></div>
              </div>

              <div className="p-3 bg-black/40 border-t border-cyber-700">
                 <div className="flex gap-2">
                   <input 
                     type="text" 
                     value={userInput}
                     onChange={(e) => setUserInput(e.target.value)}
                     onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
                     placeholder="Ask Gaia..."
                     className="flex-1 bg-black/50 border border-gray-700 rounded px-3 py-2 text-xs focus:outline-none focus:border-cyber-accent text-white font-mono"
                   />
                   <button 
                     onClick={handleSendMessage}
                     disabled={isProcessing}
                     className="p-2 bg-cyber-800 border border-cyber-700 rounded text-cyber-accent hover:bg-cyber-700 disabled:opacity-50"
                   >
                     <MessageSquare size={16} />
                   </button>
                 </div>
              </div>
           </div>
        </div>

      </main>

      {/* Live Overlay */}
      {liveMode && (
        <LiveAudio 
          onClose={() => setLiveMode(false)}
          onCapture={handleCapture}
          onTranscript={(text, isUser) => {
             // Optional: Add to main chat history for continuity
             if (!isUser) { // only model responses
                setChatMessages(prev => [...prev, {
                  id: crypto.randomUUID(),
                  role: 'model',
                  text: `[LIVE TRANSCRIPT] ${text}`,
                  timestamp: Date.now()
                }]);
             }
          }}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import CameraFeed, { CameraHandle } from './components/CameraFeed';
import LiveAudio from './components/LiveAudio';
import Timeline from './components/Timeline';
import { CapturedImage, MonitorSettings, ChatMessage } from './types';
import { 
  analyzeImage, 
  sendMessage, 
  generateGrowthReport
} from './services/geminiService';
import { 
  Leaf, 
  Play, 
  Square, 
  MessageSquare, 
  Globe, 
  BrainCircuit, 
  Clock, 
  Eye, 
  FileText, 
  PlayCircle, 
  EyeOff, 
  Trash2, 
  Terminal, 
  Settings, 
  Camera, 
  Cpu, 
  Radio, 
  Calendar, 
  Video, 
  Sun, 
  Power, 
  X,
  Zap,
  Activity
} from 'lucide-react';

const App: React.FC = () => {
  const [active, setActive] = useState(false);
  const [isCameraEnabled, setIsCameraEnabled] = useState(true);
  const [images, setImages] = useState<CapturedImage[]>([]);
  const [settings, setSettings] = useState<MonitorSettings>({
    intervalHours: 1.5,
    autoAnalyze: true,
    wakeLockActive: true,
    facingMode: 'environment',
    resolution: 'high',
    playbackFps: 5,
    timestampPrecision: 'both',
    minConfidenceThreshold: 75,
    autoAdvance: true
  });

  const [selectedImage, setSelectedImage] = useState<CapturedImage | null>(null);
  const [liveMode, setLiveMode] = useState(false);
  const [playbackMode, setPlaybackMode] = useState(false);
  const [stealthMode, setStealthMode] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [chatMessages, setChatMessages] = useState<ChatMessage[]>([]);
  const [userInput, setUserInput] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [flash, setFlash] = useState(false);
  const [nextCaptureTime, setNextCaptureTime] = useState<number | null>(null);
  const [currentTime, setCurrentTime] = useState(new Date());

  const cameraRef = useRef<CameraHandle>(null);
  const intervalRef = useRef<any>(null);
  const wakeLockRef = useRef<any>(null);

  // Clock Update
  useEffect(() => {
    const t = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(t);
  }, []);

  // --- SCREEN WAKE LOCK ---
  // This is what allows the app to "play in background" by keeping the screen on
  const requestWakeLock = async () => {
    if ('wakeLock' in navigator && settings.wakeLockActive) {
      try {
        wakeLockRef.current = await (navigator as any).wakeLock.request('screen');
        console.log('Wake Lock Activated');
      } catch (err) {
        console.error('Wake Lock failed:', err);
      }
    }
  };

  const releaseWakeLock = async () => {
    if (wakeLockRef.current) {
      await wakeLockRef.current.release();
      wakeLockRef.current = null;
      console.log('Wake Lock Released');
    }
  };

  // --- MONITORING CYCLE ---
  const captureAndProcess = async () => {
    if (cameraRef.current) {
      setFlash(true);
      setTimeout(() => setFlash(false), 150);

      const dataUrl = cameraRef.current.capture();
      if (dataUrl) {
        const id = Date.now().toString();
        const newImage: CapturedImage = { id, timestamp: Date.now(), dataUrl };
        setImages(prev => [...prev, newImage]);

        // Schedule next
        setNextCaptureTime(Date.now() + (settings.intervalHours * 3600000));

        if (settings.autoAnalyze) {
          try {
            const prompt = "Analyze plant growth. Detect species, health status (Healthy, Stressed, Critical), and stage. Format: [HEALTH: status][STAGE: stage][ADVICE: text]";
            const analysis = await analyzeImage(dataUrl, prompt);

            // Extract health status for the UI badges
            let health: any = 'HEALTHY';
            if (analysis.includes('CRITICAL')) health = 'CRITICAL';
            else if (analysis.includes('STRESSED')) health = 'STRESSED';

            setImages(prev => prev.map(img => img.id === id ? { ...img, analysis, healthStatus: health } : img));
          } catch (e) { console.error("AI Analysis Error", e); }
        }
      }
    }
  };

  useEffect(() => {
    if (active) {
      requestWakeLock();
      captureAndProcess(); // Initial capture
      const ms = settings.intervalHours * 3600000;
      intervalRef.current = setInterval(captureAndProcess, ms);
    } else {
      releaseWakeLock();
      if (intervalRef.current) clearInterval(intervalRef.current);
      setNextCaptureTime(null);
    }
    return () => {
      clearInterval(intervalRef.current);
      releaseWakeLock();
    };
  }, [active, settings.intervalHours]);

  const handleChatSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!userInput.trim()) return;
    const msg: ChatMessage = { id: Date.now().toString(), role: 'user', text: userInput, timestamp: Date.now() };
    setChatMessages(prev => [...prev, msg]);
    setUserInput('');
    setIsProcessing(true);
    try {
      const response = await sendMessage(chatMessages, msg.text);
      setChatMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', text: response.text || "...", timestamp: Date.now() }]);
    } catch (e) { console.error(e); } finally { setIsProcessing(false); }
  };

  const getCountdown = () => {
    if (!nextCaptureTime) return null;
    const diff = nextCaptureTime - currentTime.getTime();
    if (diff <= 0) return "CAPTURING...";
    const h = Math.floor(diff / 3600000);
    const m = Math.floor((diff % 3600000) / 60000);
    const s = Math.floor((diff % 60000) / 1000);
    return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  return (
    <div className="min-h-screen bg-[#020617] text-gray-200 font-sans flex flex-col selection:bg-cyber-accent selection:text-black">

      {/* Stealth Mode Overlay (Clock only) */}
      {stealthMode && (
        <div 
          className="fixed inset-0 bg-black z-[100] flex flex-col items-center justify-center cursor-pointer"
          onDoubleClick={() => setStealthMode(false)}
        >
          <div className="text-[12vw] font-mono font-thin text-white/10 tracking-tighter select-none">
            {currentTime.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' })}
          </div>
          <div className="mt-4 flex items-center gap-4 text-cyber-accent/20 font-mono text-xs uppercase tracking-[0.4em]">
            <Activity size={14} className="animate-pulse" /> Monitoring Active
          </div>
          <p className="absolute bottom-10 text-[10px] text-white/5 font-mono">DBL CLICK TO RESTORE HUD</p>
        </div>
      )}

      {/* Header HUD */}
      <header className="border-b border-white/5 bg-black/40 backdrop-blur-xl p-4 sticky top-0 z-30 flex justify-between items-center px-8">
        <div className="flex items-center gap-4">
          <div className="relative">
            <Leaf className="text-cyber-accent w-7 h-7 drop-shadow-[0_0_12px_rgba(132,204,22,0.6)] animate-pulse"/>
            <div className="absolute -top-1 -right-1 w-2 h-2 bg-cyber-success rounded-full animate-ping"></div>
          </div>
          <div>
            <h1 className="font-mono font-bold tracking-tighter text-xl text-white">CHRONOS <span className="text-cyber-accent">GAIA</span></h1>
            <p className="text-[9px] font-mono text-gray-500 tracking-widest uppercase">Autonomous Botanical Intelligence</p>
          </div>
        </div>

        <div className="flex items-center gap-3">
          {active && (
            <div className="hidden md:flex items-center gap-3 bg-black/60 px-4 py-2 rounded-lg border border-cyber-accent/20 mr-4">
              <Clock size={14} className="text-cyber-accent animate-spin-slow" />
              <div className="flex flex-col">
                <span className="text-[8px] text-gray-500 font-mono uppercase">Next Snap In</span>
                <span className="text-xs font-mono text-white tracking-widest">{getCountdown()}</span>
              </div>
            </div>
          )}
          <button onClick={() => setStealthMode(true)} className="p-2.5 rounded-xl border border-white/5 hover:bg-white/5 transition-all text-gray-400">
            <EyeOff size={20} />
          </button>
          <button onClick={() => setShowSettings(!showSettings)} className={`p-2.5 rounded-xl border transition-all ${showSettings ? 'bg-cyber-accent/20 border-cyber-accent text-cyber-accent' : 'border-white/5 text-gray-400 hover:bg-white/5'}`}>
            <Settings size={20}/>
          </button>
          <button onClick={() => setLiveMode(true)} className="flex items-center gap-2 px-5 py-2.5 bg-cyber-accent text-black rounded-xl font-bold text-xs tracking-widest hover:brightness-110 transition-all shadow-[0_0_20px_rgba(132,204,22,0.2)]">
            <Radio size={16}/> LIVE LINK
          </button>
        </div>
      </header>

      <div className="flex-1 flex overflow-hidden">
        {/* Main Interface */}
        <main className="flex-1 p-8 space-y-8 overflow-y-auto custom-scrollbar">
          <div className="grid lg:grid-cols-12 gap-8">

            {/* Viewport Area */}
            <div className="lg:col-span-8 space-y-8">
              <div className="aspect-video bg-black rounded-3xl overflow-hidden border border-cyber-700/30 relative shadow-2xl ring-1 ring-white/5 group">
                {/* Flash Effect */}
                <div className={`absolute inset-0 bg-white z-[60] pointer-events-none transition-opacity duration-300 ${flash ? 'opacity-40' : 'opacity-0'}`}></div>

                {playbackMode && selectedImage ? (
                  <img src={selectedImage.dataUrl} className="w-full h-full object-contain bg-[#050505]" alt="Selected Frame" />
