                  </div>
                </div>
              </div>

              {/* Timeline Horizontal */}
              <div className="bg-[#0f172a]/40 p-6 rounded-3xl border border-white/5 backdrop-blur-md shadow-inner">
                <div className="flex justify-between items-center mb-6">
                  <h3 className="text-[10px] font-mono text-gray-500 flex items-center gap-3 uppercase tracking-widest">
