                <div className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar">
                  {chatMessages.length === 0 && (
                    <div className="h-full flex flex-col items-center justify-center text-gray-700/30">
                      <BrainCircuit size={48} className="mb-4" />
                      <p className="text-[10px] font-mono text-center tracking-[0.3em] uppercase">Neural Link Idle</p>
                    </div>
                  )}
                  {chatMessages.map(m => (
                    <div key={m.id} className={`flex flex-col ${m.role === 'user' ? 'items-end' : 'items-start'}`}>
                      <div className={`p-4 rounded-2xl text-xs leading-relaxed max-w-[90%] shadow-sm ${m.role === 'user' ? 'bg-cyber-accent/10 text-cyber-accent border border-cyber-accent/20' : 'bg-white/5 border border-white/10 text-gray-300'}`}>
