            </div>
          </aside>
        )}
      </div>

      {liveMode && <LiveAudio onClose={() => setLiveMode(false)} onCapture={handleChatSubmit as any} onTranscript={(t, u) => setChatMessages(p => [...p, {id: Date.now().toString(), role: u ? 'user' : 'model', text: t, timestamp: Date.now()}])} />}
    </div>
  );
};

export default App;

