<uses-permission android:name="android.permission.WAKE_LOCK" />
  `.trim();

  const copyCode = () => {
    navigator.clipboard.writeText(androidCode);
    setCopied(true);
    triggerHaptic([50, 50]);
    setTimeout(() => setCopied(false), 2000);
  };

  // --- BIO RHYTHM VISUALIZER ---
  const BioRhythm = () => {
    const canvasRef = useRef<HTMLCanvasElement>(null);
    useEffect(() => {
      const cvs = canvasRef.current;
      if(!cvs) return;
      const ctx = cvs.getContext('2d');
      let frame = 0;
      const draw = () => {
        if(!ctx) return;
        frame++;
        ctx.clearRect(0,0,100,40);
        ctx.beginPath();
        ctx.moveTo(0, 20);
        for(let i=0; i<100; i+=2) {
          const y = 20 + Math.sin(i * 0.2 + frame * 0.1) * 10 * Math.random();
          ctx.lineTo(i, y);
        }
        ctx.strokeStyle = '#22d3ee';
        ctx.lineWidth = 1;
        ctx.stroke();
        requestAnimationFrame(draw);
      };
      draw();
    }, []);
    return <canvas ref={canvasRef} width="100" height="40" className="opacity-60" />;
  };

  return (
