                  <button 
                    onClick={() => { setSettings({...settings, facingMode: 'user'}); triggerHaptic(20); }}
                    className={`flex-1 py-3 rounded-xl border text-[10px] font-bold uppercase transition-all ${settings.facingMode === 'user' ? 'bg-white text-black border-transparent' : 'bg-black/40 border-white/5 text-gray-500'}`}
