import React, { useState, useEffect, useRef } from 'react';
import CameraFeed, { CameraHandle } from './components/CameraFeed';
import LiveAudio from './components/LiveAudio';
import Timeline from './components/Timeline';
import { CapturedImage, MonitorSettings, ChatMessage } from './types';
import { 
  analyzeImage, 
  sendMessage, 
  generateGrowthReport
} from './services/geminiService';
import { 
  Leaf, 
  Play, 
  Square, 
  MessageSquare, 
  Globe, 
  BrainCircuit, 
  Clock, 
  Eye, 
  FileText, 
  PlayCircle, 
  EyeOff, 
  Trash2, 
  Terminal, 
  Settings, 
  Camera, 
  Cpu, 
  Radio, 
  Calendar, 
  Video, 
  Sun, 
  Power, 
  X,
  Zap,
  Activity,
  Code,
  Smartphone,
  Copy,
  Check,
  AlertTriangle
} from 'lucide-react';

const App: React.FC = () => {
  const [active, setActive] = useState(false);
  const [isCameraEnabled, setIsCameraEnabled] = useState(true);
  const [images, setImages] = useState<CapturedImage[]>([]);
  const [settings, setSettings] = useState<MonitorSettings>({
    intervalHours: 1.5,
    autoAnalyze: true,
    wakeLockActive: true,
    facingMode: 'environment',
    resolution: 'high',
    playbackFps: 5,
    timestampPrecision: 'both',
    minConfidenceThreshold: 75,
    autoAdvance: true
  });

  const [selectedImage, setSelectedImage] = useState<CapturedImage | null>(null);
  const [liveMode, setLiveMode] = useState(false);
  const [playbackMode, setPlaybackMode] = useState(false);
  const [stealthMode, setStealthMode] = useState(false);
  const [showSettings, setShowSettings] = useState(false);

  // Deployment State
  const [showAndroidCode, setShowAndroidCode] = useState(false);
  const [codeLang, setCodeLang] = useState<'kotlin' | 'java'>('kotlin');

  const [chatMessages, setChatMessages] = useState<ChatMessage[]>([]);
  const [userInput, setUserInput] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [flash, setFlash] = useState(false);
  const [nextCaptureTime, setNextCaptureTime] = useState<number | null>(null);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [copied, setCopied] = useState(false);

  const cameraRef = useRef<CameraHandle>(null);
  const intervalRef = useRef<any>(null);
  const wakeLockRef = useRef<any>(null);

  // Haptics Helper
  const triggerHaptic = (pattern: number | number[] = 20) => {
    if (navigator.vibrate) {
      navigator.vibrate(pattern);
    }
  };

  // Clock Update
  useEffect(() => {
    const t = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(t);
  }, []);

  // --- SCREEN WAKE LOCK ---
  const requestWakeLock = async () => {
    if ('wakeLock' in navigator && settings.wakeLockActive) {
      try {
        wakeLockRef.current = await (navigator as any).wakeLock.request('screen');
        console.log('Wake Lock Activated');
      } catch (err) {
        console.error('Wake Lock failed:', err);
      }
    }
  };

  const releaseWakeLock = async () => {
    if (wakeLockRef.current) {
      await wakeLockRef.current.release();
      wakeLockRef.current = null;
      console.log('Wake Lock Released');
    }
  };

  // --- MONITORING CYCLE ---
  const captureAndProcess = async () => {
    if (cameraRef.current) {
      setFlash(true);
      triggerHaptic([50, 50, 50]);
      setTimeout(() => setFlash(false), 150);

      const dataUrl = cameraRef.current.capture();
      if (dataUrl) {
        const id = Date.now().toString();
        const newImage: CapturedImage = { id, timestamp: Date.now(), dataUrl };
        setImages(prev => [...prev, newImage]);

        // Schedule next
        setNextCaptureTime(Date.now() + (settings.intervalHours * 3600000));

        if (settings.autoAnalyze) {
          try {
            const prompt = "Analyze plant growth. Detect species, health status (Healthy, Stressed, Critical), and stage. Format: [HEALTH: status][STAGE: stage][ADVICE: text]";
            const analysis = await analyzeImage(dataUrl, prompt);

            // Extract health status for the UI badges
            let health: any = 'HEALTHY';
            if (analysis.includes('CRITICAL')) health = 'CRITICAL';
            else if (analysis.includes('STRESSED')) health = 'STRESSED';

            setImages(prev => prev.map(img => img.id === id ? { ...img, analysis, healthStatus: health } : img));
          } catch (e) { console.error("AI Analysis Error", e); }
        }
      }
    }
  };

  useEffect(() => {
    if (active) {
      requestWakeLock();
      captureAndProcess(); // Initial capture
      const ms = settings.intervalHours * 3600000;
      intervalRef.current = setInterval(captureAndProcess, ms);
    } else {
      releaseWakeLock();
      if (intervalRef.current) clearInterval(intervalRef.current);
      setNextCaptureTime(null);
    }
    return () => {
      clearInterval(intervalRef.current);
      releaseWakeLock();
    };
  }, [active, settings.intervalHours]);

  const handleChatSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!userInput.trim()) return;
    triggerHaptic(30);
    const msg: ChatMessage = { id: Date.now().toString(), role: 'user', text: userInput, timestamp: Date.now() };
    setChatMessages(prev => [...prev, msg]);
    setUserInput('');
    setIsProcessing(true);
    try {
      const response = await sendMessage(chatMessages, msg.text);
      triggerHaptic([20, 30, 20]);
      setChatMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', text: response.text || "...", timestamp: Date.now() }]);
    } catch (e) { console.error(e); } finally { setIsProcessing(false); }
  };

  const getCountdown = () => {
    if (!nextCaptureTime) return null;
    const diff = nextCaptureTime - currentTime.getTime();
    if (diff <= 0) return "CAPTURING...";
    const h = Math.floor(diff / 3600000);
    const m = Math.floor((diff % 3600000) / 60000);
    const s = Math.floor((diff % 60000) / 1000);
    return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  // --- ANDROID STUDIO CODE GENERATOR ---
  const getAndroidCode = () => {
    if (codeLang === 'kotlin') {
      return `
