                 >
                   <div className="flex items-center gap-3">
                     <Smartphone size={18} className="text-cyber-accent" />
                     <div className="text-left">
                       <h3 className="text-[11px] font-bold text-white uppercase">Deploy to Android</h3>
                       <p className="text-[9px] text-cyber-accent/60 font-mono">GENERATE STUDIO CODE</p>
                     </div>
                   </div>
                   <Code size={14} className="text-cyber-accent"/>
                 </button>

                 {showAndroidPortal && (
                   <div className="p-4 bg-black/40 rounded-xl border border-white/10 space-y-4 animate-in slide-in-from-top-2">
                     <div className="flex items-start gap-2 text-cyber-warn/80">
                       <AlertTriangle size={14} className="mt-1 shrink-0" />
                       <p className="text-[9px] font-mono leading-relaxed">
                         To fix the "Hello Android" screen, you MUST delete all code in <span className="text-white">MainActivity.kt</span> and paste this snippet.
                       </p>
                     </div>
                     <div className="relative">
                        <pre className="text-[9px] font-mono bg-black p-3 rounded border border-white/5 overflow-x-auto text-gray-500 leading-tight">
                          {androidKotlinCode}
                        </pre>
                        <button 
                          onClick={copyAndroidCode}
                          className="absolute top-2 right-2 p-1.5 bg-white/5 hover:bg-white/10 rounded border border-white/10 transition-all"
                        >
                          {copied ? <Check size={12} className="text-green-500"/> : <Copy size={12}/>}
                        </button>
                     </div>
                     <div className="text-[8px] font-mono text-gray-600 italic">
                       * Replace the placeholder URL with your hosted web address.
                     </div>
                   </div>
                 )}
              </section>

              {/* Capture Frequency */}
              <section className="space-y-4">
                <div className="flex justify-between items-center text-[10px] font-mono uppercase tracking-[0.1em]">
                  <span className="text-gray-500 flex items-center gap-2 font-bold"><Clock size={12}/> Interval</span>
                  <span className="text-cyber-accent font-bold">{settings.intervalHours}h</span>
                </div>
                <input 
                  type="range" 
                  min="0.1" max="24" step="0.1" 
                  value={settings.intervalHours} 
                  onChange={e => setSettings({...settings, intervalHours: parseFloat(e.target.value)})} 
                  className="w-full h-1 bg-[#1a2333] rounded-lg appearance-none cursor-pointer accent-cyber-accent"
                />
              </section>

              {/* Toggles */}
              <section className="space-y-3">
                <div className="flex items-center justify-between p-3.5 bg-black/40 rounded border border-white/5 transition-colors hover:border-white/10 group">
                  <span className="text-[11px] font-bold text-gray-300">Auto-Analyze</span>
                  <button 
                    onClick={() => setSettings({...settings, autoAnalyze: !settings.autoAnalyze})} 
                    className={`w-9 h-5 rounded-full relative transition-all duration-300 ${settings.autoAnalyze ? 'bg-cyber-accent' : 'bg-gray-700'}`}
                  >
                    <div className={`absolute top-1 w-3 h-3 rounded-full bg-white transition-all ${settings.autoAnalyze ? 'right-1' : 'left-1'}`}></div>
                  </button>
                </div>
                <div className="flex items-center justify-between p-3.5 bg-black/40 rounded border border-white/5 transition-colors hover:border-white/10 group">
                  <span className="text-[11px] font-bold text-gray-300">Prevent Sleep</span>
                  <button 
                    onClick={() => setSettings({...settings, wakeLockActive: !settings.wakeLockActive})} 
                    className={`w-9 h-5 rounded-full relative transition-all duration-300 ${settings.wakeLockActive ? 'bg-cyber-accent' : 'bg-gray-700'}`}
                  >
                    <div className={`absolute top-1 w-3 h-3 rounded-full bg-white transition-all ${settings.wakeLockActive ? 'right-1' : 'left-1'}`}></div>
                  </button>
                </div>
              </section>

              {/* Optics */}
              <section className="space-y-4">
                <label className="text-[10px] font-mono text-gray-500 uppercase tracking-widest font-bold">Lens Selection</label>
                <div className="grid grid-cols-2 gap-2">
                  <button 
                    onClick={() => setSettings({...settings, facingMode: 'environment'})} 
                    className={`py-2 text-[10px] rounded border transition-all ${settings.facingMode === 'environment' ? 'bg-white text-black border-transparent' : 'bg-black/20 text-gray-500 border-white/5'}`}
                  >
                    REAR
                  </button>
                  <button 
                    onClick={() => setSettings({...settings, facingMode: 'user'})} 
                    className={`py-2 text-[10px] rounded border transition-all ${settings.facingMode === 'user' ? 'bg-white text-black border-transparent' : 'bg-black/20 text-gray-500 border-white/5'}`}
                  >
                    FRONT
                  </button>
                </div>
              </section>
            </div>
          </aside>
        )}
      </div>

      {liveMode && <LiveAudio onClose={() => setLiveMode(false)} onCapture={handleManualCapture} onTranscript={(t, u) => setChatMessages(p => [...p, {id: Date.now().toString(), role: u ? 'user' : 'model', text: t, timestamp: Date.now()}])} />}
    </div>
  );
};

export default App;
